head.script:
// 협력사: NTIS/배차관리/송장회수등록(Barcode)

scwin.memJson = $c.data.getMemInfo();

scwin.sUserId  = scwin.memJson.userId;
scwin.sUserNm = scwin.memJson.userNm;
scwin.sUserClsCd = $c.gus.cfIsNull(scwin.memJson.userClsCd) ? "" : scwin.memJson.userClsCd;   
scwin.sClntNo = $c.gus.cfIsNull(scwin.memJson.clntNo) ? "" : scwin.memJson.clntNo;   
scwin.sClntNm = $c.gus.cfIsNull(scwin.memJson.clntNm) ? "" : scwin.memJson.clntNm;   

scwin.sDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strFromDate = scwin.sDate;			// 현재년월일을 구한다.
scwin.strToDate = $c.date.getServerDateTime("dd");	// 현재일자를 구한다.
scwin.strDate = scwin.strFromDate;

scwin.userClsCd = scwin.sUserClsCd;
scwin.focusBilgMchtCd = false;



