//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    // $c.gus.cfDisableObjects([ed_progress, bilgMcht]);
    // udc name부분 disabled 안되는데어케함..

    //ed_invoiceNo.text = "2000161";
    ed_progress.setValue("Reading...");

    ed_invoiceNo.focus();
};



//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {
    ed_progress.setValue("준비중...");

    ds_cond.set("invoiceNo", ed_invoiceNo.getValue());
    $c.sbm.execute(sbm_retrieve);
};



//-------------------------------------------------------------------------
// TODAY HISTORY 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveTodayHistory = function() {
    if (chk_autoRetrieveHist.getValue() != "1") {
        return;
    }

    ds_condHist.set("history", "T");
    $c.sbm.execute(sbm_retrieveHist);
};


scwin.f_Save = function() {
    if (scwin.f_chkUpdateYn) {
        ed_progress.setValue("이미 처리한 내역입니다.");
        return;
    }

    // ds_out.UseChangeInfo = false;
    $c.sbm.execute(sbm_save);
};


scwin.f_chkUpdateYn = function() {
    var retVal = false;

    for (var i = 0; i < ds_out.getTotalRow(); i++) {
        if (ds_out.getCellData(i, "invoiceRetrvDtm") != "") {
            retVal = true;
        }
    }

    return retVal;
};


scwin.ed_invoiceNo_onkeydown = function (e) { // =f_keyDown
    // var code = (window.event) ? window.event.keyCode : eventObject.keyCode;

    if (scwin.focusBilgMchtCd) {
        return;
    }

    if (ed_invoiceNo.getValue().length < 7) {
        // ed_invoiceNo.text = ed_invoiceNo.text+String.fromCharCode(window.event.keyCode);
    } else {
        if (e.keyCode == 13) {
            if (ed_invoiceNo.getValue().length != 7) {
                ed_progress.setValue("송장번호 자리수가 맞지 않습니다.");
                return;
            }
            scwin.f_Retrieve();
        } 
        // else {
        //     ed_invoiceNo.setValue("");
            // ed_invoiceNo.text = String.fromCharCode(window.event.keyCode);
        // }
    }
};


scwin.f_toExcel = async function() {
    var fileName = "송장회수등록(Barcode)";
    await $c.data.downloadGridViewExcel(gr_out, { fileName: fileName + ".xlsx", sheetName: fileName });
};


scwin.f_Reset =  function() {
    ed_invoiceNo.setValue("");
};


//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openPopUp(disGubun, '', pVal, 'T', 'T');
    }
};


//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_openPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    var rtnList = new Array();

    if(disGubun == "1"){
        udc_bilgMchtCd.setSelectId("retrieveBilgMchtList");
        udc_bilgMchtCd.cfCommonPopUp(scwin.udc_bilgMchtCd_callbackFun          // XML상의 SELECT ID  
                                ,pCode                  // 화면에서의 ??? Code Element의  Value
                                ,pName                  // 화면에서의 ??? Name Element의  Value
                                ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null                   // Title순서  
                                ,null                   // 보여주는 각 컬럼들의 폭    
                                ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                                ,null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                                ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                ,null                   // 윈도우 위치 Y좌표   
                                ,null                   // 윈도우 위치 X좌표
                                ,null                   // 중복체크여부   ("F")
                                ,pAllSearch                 // 전체검색허용여부 ("F")
                                ,"청구화주,청구화주코드,청구화주명"                // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                ); 
    }
};

scwin.udc_bilgMchtCd_callbackFun = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, bilgMchtCd, bilgMcht);
};

scwin.sbm_save_submitdone = function (e) {
    ed_progress.setValue("회수저장완료");
    scwin.f_RetrieveTodayHistory();
};


scwin.sbm_retrieve_submitdone = function (e) {
    var rowCnt = ds_out.getTotalRow();

    if( rowCnt == 0 ){
		ed_progress.setValue("조회된 데이터가 없습니다.");
	}else{
        gr_out.setFocusedCell(0, 0, false);
    }


    totalRows.setValue(rowCnt);

	scwin.f_RetrieveTodayHistory();

    if (rowCnt > 0) {
	    ed_progress.setValue("준비중...");

		scwin.f_Save();
	}
};


scwin.sbm_retrieveHist_submitdone = function (e) {
    totalRows2.setValue(ds_todayHist.getTotalRow());
    const rowCnt = ds_todayHist.getTotalRow();

    if( rowCnt == 0 ){
	}else{
        gr_todayHist.setFocusedCell(0, 0, false);
    }
};


scwin.udc_bilgMchtCd_onblurCodeEvent = function (e) {
    scwin.focusBilgMchtCd = false;
    scwin.f_chkOpenCommonPopUp(bilgMchtCd, bilgMcht, '1');
};


scwin.udc_bilgMchtCd_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(btn_bilgMchtCd, bilgMchtCd, '1', false);
};



scwin.udc_bilgMchtCd_onclickEvent = function (e) {
    scwin.f_openPopUp('1', bilgMchtCd.getValue(), bilgMcht.getValue(), 'F', 'F');
};




scwin.gr_out_onkeydown = function (e) {
    const code = e.keyCode || e.which;
    const currentVal = ed_invoiceNo.getValue();
    //const char = String.fromCharCode(code);

    if (typeof focusBilgMchtCd !== "undefined" && focusBilgMchtCd) {
        return;
    }

    if (currentVal.length < 7) {
        // 입력 중 (필요 시 로직 추가)
    } else {
        if (code === 13) { 
            if (currentVal.length !== 7) {
                ed_progress.setValue("송장번호 자리수가 맞지 않습니다.");
                return;
            }
            scwin.f_Retrieve();
        } else {
            // ed_invoiceNo.setValue(char);
        }
    }
};
